const results = [];
function stripHtml(s) { return (s||'').replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').trim().slice(0,3000); }
for (const item of $input.all()) {
  const d = item.json;
  if (!d || !d.data || !Array.isArray(d.data)) continue;
  for (const j of d.data) {
    if (!j.job_id || !j.job_title) continue;
    results.push({ json: {
      external_id: 'js_' + j.job_id,
      title: j.job_title,
      company: j.employer_name || 'Unknown',
      description: stripHtml(j.job_description || ''),
      apply_url: j.job_apply_link || j.job_google_link || '',
      posted_at: j.job_posted_at_timestamp ? new Date(j.job_posted_at_timestamp * 1000).toISOString() : new Date().toISOString(),
      location: j.job_is_remote ? 'Remote' : [j.job_city, j.job_country].filter(Boolean).join(', '),
      source: 'jsearch'
    }});
  }
}
return results.length ? results : [{ json: { _empty: true } }];

