const newJobs = $('Merge - All Sources').all().filter(j => !j.json._empty);
let existingIds = new Set();
try {
  const existing = $('DB - Get Existing IDs').all();
  existingIds = new Set(existing.map(d => String(d.json.external_id)));
} catch (e) {}
return newJobs.filter(job => {
  const id = String(job.json.external_id);
  return id && id !== 'undefined' && !existingIds.has(id);
});

const BACKEND_TITLE_DQ = [
  '.net', 'c#', 'c sharp', 'java developer', 'java engineer',
  'python developer', 'python engineer', 'ruby developer', 'ruby engineer',
  'backend developer', 'backend engineer', 'backend dev',
  'devops', 'site reliability', 'sre', 'cloud engineer', 'cloud architect',
  'data engineer', 'data scientist', 'ml engineer', 'machine learning',
  'golang', 'go developer', 'rust developer', 'scala developer',
  'php developer', 'laravel developer', 'django developer', 'wordpress developer',
  'ios developer', 'ios engineer', 'android developer', 'android engineer',
  'kotlin developer', 'swift developer',
  'qa engineer', 'qa analyst', 'quality assurance', 'test engineer', 'sdet',
  'blockchain developer', 'solidity', 'embedded', 'firmware'
];

const BACKEND_DESC_HEAVY = [
  'asp.net', '.net core', 'spring boot', 'spring framework',
  'django', 'flask', 'laravel', 'ruby on rails',
  'hibernate', 'entity framework',
  'kafka', 'rabbitmq', 'kubernetes',
  'sql server', 'oracle database', 'pl/sql'
];

const FRONTEND_TITLE_SIGNALS = [
  'frontend', 'front-end', 'front end',
  'react', 'react native', 'react.js', 'reactjs',
  'ui developer', 'ui engineer',
  'javascript developer', 'js developer', 'typescript developer',
  'next.js', 'nextjs', 'angular developer', 'vue developer',
  'web developer', 'web engineer', 'mobile developer'
];

const PRIMARY_SKILLS   = ['react', 'react.js', 'react native', 'typescript', 'javascript', 'next.js'];
const SECONDARY_SKILLS = ['redux', 'graphql', 'tailwind', 'firebase', 'node.js', 'mui', 'material-ui', 'expo', 'webpack', 'vite', 'css', 'html5'];

const ALERT_THRESHOLD = 55;

return $input.all().map(function(item) {
  const job     = item.json;
  const title   = (job.title || '').toLowerCase();
  const desc    = (job.description || '').toLowerCase();
  const combined = title + ' ' + desc;

  const backendTitleHit = BACKEND_TITLE_DQ.find(t => title.includes(t));
  if (backendTitleHit) {
    return { json: { ...job, match_score: 0, reasons: ['Backend en título: ' + backendTitleHit], is_hot_match: false } };
  }

  const hasFrontendTitle = FRONTEND_TITLE_SIGNALS.some(s => title.includes(s));
  const primaryInDesc    = PRIMARY_SKILLS.filter(s => desc.includes(s));
  if (!hasFrontendTitle && primaryInDesc.length === 0) {
    return { json: { ...job, match_score: 0, reasons: ['Sin señal frontend'], is_hot_match: false } };
  }

  const backendDescHits = BACKEND_DESC_HEAVY.filter(t => combined.includes(t));
  if (backendDescHits.length >= 3) {
    return { json: { ...job, match_score: 0, reasons: ['Backend-heavy: ' + backendDescHits.slice(0, 2).join(', ')], is_hot_match: false } };
  }

  let score = 0;
  const reasons = [];

  if (hasFrontendTitle) { score += 20; reasons.push('Frontend en título'); }
  if (title.includes('react')) { score += 15; reasons.push('React en título'); }

  const primaryScore = Math.round((primaryInDesc.length / PRIMARY_SKILLS.length) * 35);
  score += primaryScore;
  if (primaryInDesc.length > 0) { reasons.push('Skills: ' + primaryInDesc.slice(0, 4).join(', ')); }

  const secondaryMatched = SECONDARY_SKILLS.filter(s => combined.includes(s));
  score += Math.min(secondaryMatched.length * 2, 10);

  if (title.includes('senior') || title.includes('sr.') || title.includes('sr ') ||
      desc.includes('5+ years') || desc.includes('5 years') || desc.includes('senior')) {
    score += 15;
    reasons.push('Senior');
  }

  if (combined.includes('remote') || (job.location || '').toLowerCase().includes('remote')) {
    score += 5;
    reasons.push('Remote');
  }

  const finalScore = Math.min(Math.round(score), 100);

  return {
    json: { ...job, match_score: finalScore, reasons, flags: primaryInDesc, is_hot_match: finalScore >= ALERT_THRESHOLD }
  };
});
